"use client"

import * as React from "react"
import { cn } from "@/lib/utils"

export const DATA_PANEL_CARD_CLASS_NAME = "overflow-hidden rounded-[1.35rem] border border-border/70 bg-card/95 shadow-[0_1px_0_rgba(255,255,255,0.65),0_18px_48px_-32px_rgba(15,23,42,0.28)]"
export const DATA_PANEL_HEADER_CLASS_NAME = "border-b border-border/60 bg-[linear-gradient(180deg,color-mix(in_srgb,var(--background)_84%,var(--muted))_0%,color-mix(in_srgb,var(--background)_96%,transparent)_100%)] px-5 py-4 md:px-6"
export const DATA_PANEL_CONTENT_CLASS_NAME = "px-5 py-5 md:px-6 md:py-6"
export const DATA_PANEL_SECTION_CLASS_NAME = "rounded-[1.1rem] border border-border/60 bg-muted/[0.16] shadow-[inset_0_1px_0_rgba(255,255,255,0.4)]"
export const DATA_TOOLBAR_CARD_CLASS_NAME = "rounded-[1.25rem] border border-border/70 bg-card/90 px-4 py-4 shadow-[0_1px_0_rgba(255,255,255,0.55),0_16px_38px_-34px_rgba(15,23,42,0.35)]"
export const DATA_TABLE_FRAME_CLASS_NAME = "overflow-hidden rounded-[1.25rem] border border-border/70 bg-background/95 shadow-[0_1px_0_rgba(255,255,255,0.52),0_20px_45px_-40px_rgba(15,23,42,0.4)]"
export const DATA_FLOATING_BAR_CLASS_NAME = "rounded-full border border-border/70 bg-background/85 px-5 py-2.5 shadow-[0_18px_50px_-28px_rgba(15,23,42,0.45)] backdrop-blur-md supports-[backdrop-filter]:bg-background/78"
export const DATA_INPUT_CLASS_NAME = "rounded-xl border border-border/70 bg-background/90 shadow-[0_1px_0_rgba(255,255,255,0.45)] transition-colors hover:border-border focus-visible:border-ring"
export const DATA_SUBTLE_ACTION_CLASS_NAME = "rounded-xl border border-border/60 bg-background/80 text-muted-foreground transition-colors hover:border-border hover:bg-muted/40 hover:text-foreground"
export const DATA_DIVIDER_CLASS_NAME = "bg-border/60"

type DataStateTone = "neutral" | "danger" | "success"

export function dataWorkspaceStateClassName(tone: DataStateTone = "neutral"): string {
  if (tone === "danger") {
    return "rounded-[1rem] border border-destructive/25 bg-destructive/10 px-4 py-4 text-sm text-destructive shadow-[inset_0_1px_0_rgba(255,255,255,0.3)]"
  }

  if (tone === "success") {
    return "rounded-[1rem] border border-emerald-500/20 bg-emerald-500/10 px-4 py-4 text-sm text-emerald-700 shadow-[inset_0_1px_0_rgba(255,255,255,0.3)] dark:text-emerald-300"
  }

  return "rounded-[1rem] border border-dashed border-border/70 bg-muted/[0.2] px-4 py-6 text-sm text-muted-foreground shadow-[inset_0_1px_0_rgba(255,255,255,0.3)]"
}

export function dataWorkspaceTypeBadgeClassName(type?: string): string {
  const normalizedType = (type ?? "text").toLowerCase()

  if (normalizedType === "enum" || normalizedType === "select") {
    return "border-amber-300/60 bg-amber-500/10 text-amber-700 dark:text-amber-300"
  }

  if (normalizedType === "uuid" || normalizedType === "foreign-key" || normalizedType === "link") {
    return "border-sky-300/60 bg-sky-500/10 text-sky-700 dark:text-sky-300"
  }

  if (normalizedType === "datetime" || normalizedType === "date") {
    return "border-violet-300/60 bg-violet-500/10 text-violet-700 dark:text-violet-300"
  }

  if (normalizedType === "boolean") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (normalizedType === "json") {
    return "border-rose-300/60 bg-rose-500/10 text-rose-700 dark:text-rose-300"
  }

  return "border-border/70 bg-muted/45 text-muted-foreground"
}

export function dataWorkspaceMetaBadgeClassName(tone: "default" | "primary" | "success" | "danger" = "default"): string {
  if (tone === "primary") {
    return "border-border/70 bg-foreground/[0.06] text-foreground"
  }

  if (tone === "success") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (tone === "danger") {
    return "border-destructive/25 bg-destructive/10 text-destructive"
  }

  return "border-border/70 bg-background/70 text-muted-foreground"
}

export function dataWorkspaceRelationBadgeClassName(source?: string): string {
  if (source === "base") {
    return "border-border/70 bg-background/80 text-foreground"
  }

  return "border-border/70 bg-muted/50 text-muted-foreground"
}

export function dataWorkspaceRowClassName(options?: {
  interactive?: boolean
  selected?: boolean
}): string {
  return cn(
    "group border-border/50 transition-colors duration-150",
    options?.interactive && "cursor-pointer hover:bg-muted/[0.26]",
    options?.selected && "bg-foreground/[0.05] hover:bg-foreground/[0.07]",
  )
}

export interface DataWorkspaceHeaderProps {
  eyebrow?: React.ReactNode
  title: React.ReactNode
  description?: React.ReactNode
  meta?: React.ReactNode
  actions?: React.ReactNode
  className?: string
}

export function DataWorkspaceHeader({
  eyebrow,
  title,
  description,
  meta,
  actions,
  className,
}: DataWorkspaceHeaderProps) {
  return (
    <div className={cn("flex flex-col gap-4 lg:flex-row lg:items-start lg:justify-between", className)}>
      <div className="min-w-0 space-y-3">
        <div className="space-y-1.5">
          {eyebrow ? (
            <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-muted-foreground/90">
              {eyebrow}
            </div>
          ) : null}
          <div className="text-lg font-semibold leading-tight tracking-[-0.01em] text-foreground md:text-xl">
            {title}
          </div>
          {description ? (
            <div className="max-w-3xl text-sm leading-6 text-muted-foreground">
              {description}
            </div>
          ) : null}
        </div>
        {meta ? (
          <div className="flex flex-wrap items-center gap-2 text-xs text-muted-foreground">
            {meta}
          </div>
        ) : null}
      </div>
      {actions ? (
        <div className="flex shrink-0 flex-wrap items-center gap-2">
          {actions}
        </div>
      ) : null}
    </div>
  )
}

export interface DataWorkspaceStateProps extends React.HTMLAttributes<HTMLDivElement> {
  tone?: DataStateTone
  heading?: React.ReactNode
  description: React.ReactNode
}

export function DataWorkspaceState({
  tone = "neutral",
  heading,
  description,
  className,
  ...props
}: DataWorkspaceStateProps) {
  return (
    <div className={cn(dataWorkspaceStateClassName(tone), className)} {...props}>
      <div className="grid gap-1.5">
        {heading ? (
          <div className="text-sm font-medium text-foreground">
            {heading}
          </div>
        ) : null}
        <div className={cn("leading-6", tone === "neutral" ? "text-muted-foreground" : undefined)}>
          {description}
        </div>
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useReverseRelatedRecords, type ReverseRelationSelector } from "lemma-sdk/react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardHeader,
} from "@/components/ui/card"
import {
  Select,
  SelectContent,
  SelectGroup,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"
import { cn } from "@/lib/utils"
import {
  DATA_INPUT_CLASS_NAME,
  DATA_PANEL_CARD_CLASS_NAME,
  DATA_PANEL_CONTENT_CLASS_NAME,
  DATA_PANEL_HEADER_CLASS_NAME,
  DATA_SUBTLE_ACTION_CLASS_NAME,
  DATA_TABLE_FRAME_CLASS_NAME,
  DataWorkspaceHeader,
  DataWorkspaceState,
  dataWorkspaceMetaBadgeClassName,
  dataWorkspaceRelationBadgeClassName,
  dataWorkspaceRowClassName,
} from "@/components/lemma/registry-data-workspace"

export interface LemmaReverseRelatedRecordsTableProps extends React.HTMLAttributes<HTMLDivElement> {
  client: LemmaClient
  podId?: string
  tableName: string
  recordId?: string | null
  relation?: ReverseRelationSelector | null
  onRelationChange?: (relation: ReverseRelationSelector | null) => void
  fields?: string[]
  limit?: number
  title?: string
  description?: string
  emptyText?: string
  recordIdField?: string
  getRecordId?: (record: Record<string, unknown>) => string
}

function formatValue(value: unknown): string {
  if (typeof value === "string") return value
  if (typeof value === "number" || typeof value === "boolean") return String(value)
  if (value === null || typeof value === "undefined") return "—"

  try {
    return JSON.stringify(value)
  } catch {
    return String(value)
  }
}

function readRecordId(
  record: Record<string, unknown>,
  recordIdField: string,
  getRecordId?: (record: Record<string, unknown>) => string,
): string {
  if (getRecordId) {
    const customId = getRecordId(record)
    return typeof customId === "string" ? customId : ""
  }

  const value = record[recordIdField]
  if (typeof value === "string") return value
  if (typeof value === "number") return String(value)
  return ""
}

export const LemmaReverseRelatedRecordsTable = React.forwardRef<HTMLDivElement, LemmaReverseRelatedRecordsTableProps>(
  ({
    client,
    podId,
    tableName,
    recordId,
    relation,
    onRelationChange,
    fields,
    limit = 10,
    title,
    description,
    emptyText = "No child records were found for this record.",
    recordIdField = "id",
    getRecordId,
    className,
    ...props
  }, ref) => {
    const trimmedTableName = tableName.trim()
    const trimmedRecordId = typeof recordId === "string" ? recordId.trim() : ""
    const reverseState = useReverseRelatedRecords({
      client,
      podId,
      tableName: trimmedTableName,
      recordId: trimmedRecordId || null,
      relation,
      fields,
      limit,
      enabled: trimmedTableName.length > 0 && trimmedRecordId.length > 0,
    })

    if (!trimmedTableName || !trimmedRecordId) {
      return (
        <Card ref={ref} className={cn(DATA_PANEL_CARD_CLASS_NAME, className)} {...props}>
          <CardHeader className={DATA_PANEL_HEADER_CLASS_NAME}>
            <DataWorkspaceHeader
              description={description ?? "Select a record to inspect child rows that point back to it."}
              eyebrow="Reverse Relations"
              title={title ?? "Reverse Related Records"}
            />
          </CardHeader>
        </Card>
      )
    }

    return (
      <Card ref={ref} className={cn(DATA_PANEL_CARD_CLASS_NAME, className)} {...props}>
        <CardHeader className={DATA_PANEL_HEADER_CLASS_NAME}>
          <DataWorkspaceHeader
            actions={(
              <Button
                className={DATA_SUBTLE_ACTION_CLASS_NAME}
                disabled={reverseState.isLoading}
                onClick={() => {
                  void reverseState.refresh()
                }}
                type="button"
                variant="ghost"
              >
                {reverseState.isLoading ? "Refreshing..." : "Refresh"}
              </Button>
            )}
            description={description ?? "Child rows discovered from foreign keys that reference this record's table."}
            eyebrow="Reverse Relations"
            meta={(
              <>
                <Badge className={cn("rounded-full border px-2.5 py-1 text-[11px] font-medium uppercase tracking-[0.14em]", dataWorkspaceMetaBadgeClassName("primary"))} variant="outline">
                  {trimmedTableName}
                </Badge>
                <Badge className={cn("max-w-full rounded-full border px-2.5 py-1 font-mono text-[11px] font-medium uppercase tracking-[0.14em]", dataWorkspaceMetaBadgeClassName("default"))} variant="outline">
                  {trimmedRecordId}
                </Badge>
              </>
            )}
            title={title ?? "Reverse Related Records"}
          />
        </CardHeader>
        <CardContent className={cn("flex flex-col gap-4", DATA_PANEL_CONTENT_CLASS_NAME)}>
          {reverseState.relations.length > 1 ? (
            <Select
              value={reverseState.selectedRelation ? `${reverseState.selectedRelation.tableName}:${reverseState.selectedRelation.foreignKey}` : ""}
              onValueChange={(value) => {
                const [tableNameValue, foreignKeyValue] = value.split(":")
                onRelationChange?.(
                  tableNameValue && foreignKeyValue
                    ? { tableName: tableNameValue, foreignKey: foreignKeyValue }
                    : null,
                )
              }}
            >
              <SelectTrigger className={DATA_INPUT_CLASS_NAME} id="lemma-reverse-related-relation">
                <SelectValue placeholder="Select a reverse relation" />
              </SelectTrigger>
              <SelectContent>
                <SelectGroup>
                  {reverseState.relations.map((entry) => (
                    <SelectItem key={`${entry.tableName}:${entry.foreignKey}`} value={`${entry.tableName}:${entry.foreignKey}`}>
                      {entry.label}
                    </SelectItem>
                  ))}
                </SelectGroup>
              </SelectContent>
            </Select>
          ) : null}

          {reverseState.error ? (
            <DataWorkspaceState description={reverseState.error.message} tone="danger" />
          ) : null}

          {reverseState.isLoading && reverseState.records.length === 0 ? (
            <DataWorkspaceState description="Loading reverse-related records..." heading="Finding child rows" />
          ) : null}

          {!reverseState.isLoading && reverseState.relations.length === 0 ? (
            <DataWorkspaceState description="No reverse relations were discovered for this table." heading="No reverse relations" />
          ) : null}

          {!reverseState.isLoading && reverseState.relations.length > 0 && reverseState.records.length === 0 ? (
            <DataWorkspaceState description={emptyText} heading="No child rows" />
          ) : null}

          {reverseState.records.length > 0 && reverseState.columns.length > 0 ? (
            <div className={DATA_TABLE_FRAME_CLASS_NAME}>
              <Table>
                <TableHeader className="bg-muted/[0.3]">
                  <TableRow className="hover:bg-transparent">
                    {reverseState.columns.map((column) => (
                      <TableHead key={column.key} className="align-top border-b border-border/60 px-4 py-3">
                        <div className="grid gap-2">
                          <div className="text-sm font-medium text-foreground">{column.label}</div>
                          <Badge className={cn("w-fit rounded-full border px-2.5 py-1 text-[10px] font-medium uppercase tracking-[0.14em]", dataWorkspaceRelationBadgeClassName("related"))} variant="outline">
                            {column.field}
                          </Badge>
                        </div>
                      </TableHead>
                    ))}
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {reverseState.records.map((record, index) => (
                    <TableRow key={readRecordId(record, recordIdField, getRecordId) || index} className={dataWorkspaceRowClassName()}>
                      {reverseState.columns.map((column) => (
                        <TableCell key={column.key} className="max-w-[240px] px-4 py-3 align-top">
                          <div className="truncate text-sm leading-6 text-foreground/90" title={formatValue(record[column.field])}>
                            {formatValue(record[column.field])}
                          </div>
                        </TableCell>
                      ))}
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          ) : null}
        </CardContent>
      </Card>
    )
  },
)
LemmaReverseRelatedRecordsTable.displayName = "LemmaReverseRelatedRecordsTable"
